/*
* component: swc_Clock
* cycletime: 50
* description: Runnable
* events: 
* name: CLOCK_input_run
* shortname: input
* signalIN: so_button
* signalOUT: so_event
* task: tsk_io
*/
void CLOCK_input_run(RTE_event ev){
	
	/* USER CODE START CLOCK_input_run */
    
    SC_BUTTON_data_t myButton = SC_BUTTON_INIT_DATA;
    SC_EVENT_data_t myEvent   = SC_EVENT_INIT_DATA;
    
    //This runnable is being called every 50 ms, therefore we need a variable that is incremented in 50, 
    //once it reaches 2000, it should set the longpress event. 
    
    static uint16_t timeCounter = 0;
    
    SC_BUTTON_driverIn(&myButton);
    
    if(TRUE == myButton.buttonRightPressed)
    {
        if(2000 > timeCounter) //2000 will be set as the time used for the right press
        {
            timeCounter = timeCounter + 50; //50 because this runnable is called every 50 miliseconds. 
        }
        else if(2000 <= timeCounter)
        {
            myEvent.m_ev = EV_KEYRIGHTLONGPRESS;
            
            RTE_SC_EVENT_set(&SO_EVENT_signal, myEvent);
            
            timeCounter = 0;
        }
        else
        {
            //Intended to do nothing.
        }
    }
    else
    {
        timeCounter = 0;
    }
    
    /* USER CODE END CLOCK_input_run */
}

