//Calback Function for the 1 Minute alarm
void clbk_1s()
{
    static uint8_t secondCounter = 0;
    
    secondCounter++;
    
    if(60 <= secondCounter)
    {
        SC_EVENT_data_t myEv;
        myEv.m_ev = EV_1MIN;  
        secondCounter = 0;
        RTE_SC_EVENT_set(&SO_EVENT_signal, myEv);
    }
    else
    {
        //Intended to do nothing.
    }
}

//Calback Function for the 250 ms alarm
void clbk_250ms()
{
    SC_EVENT_data_t myEv;
    myEv.m_ev = EV_250MS;
    
    RTE_SC_EVENT_set(&SO_EVENT_signal, myEv);
}

